# [doc = " **Home-checked** variant of [`lookup_data`] (CRITICAL #2 fix, DN-112 Rank 1 / M-1036 residual"] # [doc = " close). Used at the pattern-normalization call sites ([`normalize_pattern`], shared by"] # [doc = " `Cx::check_pattern` at check-time and the elaborator) — the sites where [`lookup_data`]'s own"] # [doc = " bare-keyed fallback was found to be reachable from **inside the checker itself**, not merely"] # [doc = " elaboration, making the type/runtime mismatch **checker-accepted** rather than an elaboration-only"] # [doc = " curiosity (see the corrected doc comment on [`lookup_data`] above)."] # [doc = ""] # [doc = " When the exact-key lookup misses and the bare-local fallback would resolve a **qualified** `name`"] # [doc = " (one with a `home::` prefix) against a `DataInfo` whose own [`DataInfo::home`] is **different**"] # [doc = " from that prefix — the exact same-nodule-shadow-plus-legitimate-cross-nodule-reach shape — this"] # [doc = " **refuses explicitly** (G2) rather than silently proceeding with the wrong declaration's"] # [doc = " ctors/field-shape. This is the **conservative (b) closure**, not the full (a) correct-home"] # [doc = " resolution: a single bare-keyed registry (own decls shadow imports, RFC-0006 §4.3) holds at most"] # [doc = " ONE `DataInfo` per bare name, so once a nodule locally shadows a foreign type's bare name, the"] # [doc = " foreign type's own `DataInfo` is not reachable from `types` at all — there is nothing correct to"] # [doc = " resolve against here. **The full (a) fix — resolving against the foreign type's own `DataInfo`"] # [doc = " via per-import-provenance-scoped resolution — needs a materially larger change in `crate::mono`"] # [doc = " (per-import registries, not one merged bare-keyed map) and is an explicit, disclosed residual, not"] # [doc = " silently deferred (G2/VR-5).** A false-refuse of the legitimate shadow+cross-nodule-pattern shape"] # [doc = " is sound (conservative); the prior false-accept was not."] # [doc = ""] # [doc = " # Errors"] # [doc = " A [`CheckError`] iff `name` is not registered at all under its own bare key (an internal"] # [doc = " consistency violation — the same condition [`lookup_data`]'s callers previously `.expect()`ed,"] # [doc = " now surfaced never-silently instead of panicking), or iff `name` is nodule-qualified and its home"] # [doc = " prefix does not match the resolved [`DataInfo::home`] (the shadow/home-mismatch case above)."] pub (crate) fn lookup_data_home_checked < 'a > (types : & 'a BTreeMap < String , DataInfo > , name : & str , site : & str ,) -> Result < & 'a DataInfo , CheckError > { if let Some (info) = types . get (name) { return Ok (info) ; } let local = ty_local_name (name) ; let Some (info) = types . get (local) else { return Err (CheckError :: new (site , format ! ("internal: data type `{name}` is not registered in this nodule's own type \
                 registry — a checked type escaped registration (report this; never a silent \
                 default, G2)") ,)) ; } ; if let Some (home) = data_home_mismatch (name , info) { return Err (CheckError :: new (site , data_home_mismatch_message (name , home , info) ,)) ; } Ok (info) }

# [doc = " One-sided **unification** of a declared type (which may contain [`Ty::Var`] parameters) against a"] # [doc = " concrete `actual` type, accumulating the parameter substitution `s` (RFC-0007 §11.3). Used to"] # [doc = " **infer** a generic function's type arguments from its call-site argument types, and a constructor's"] # [doc = " from its field arguments. A parameter is bound at most once; a second, conflicting binding is an"] # [doc = " explicit mismatch (never a silent re-coercion — G2/VR-5). No `Swap` is ever inserted: a"] # [doc = " representation-level disagreement (`Binary{8}` vs `Binary{16}`) is an explicit error, not a"] # [doc = " conversion (S1)."] pub (crate) fn unify (site : & str , decl : & Ty , actual : & Ty , s : & mut BTreeMap < String , Ty > ,) -> Result < () , CheckError > { match (decl , actual) { (Ty :: Var (v) , _) => match s . get (v) { Some (bound) if bound != actual => Err (CheckError :: new (site , format ! ("type parameter `{v}` would have to be both {bound} and {actual} — \
                     an ambiguous instantiation, not a guess (RFC-0007 §11.3)") ,)) , _ => { s . insert (v . clone () , actual . clone ()) ; Ok (()) } } , (_ , Ty :: Var (_)) if decl == actual => Ok (()) , (Ty :: Data (n1 , a1) , Ty :: Data (n2 , a2)) if n1 == n2 && a1 . len () == a2 . len () => { for (d , a) in a1 . iter () . zip (a2) { unify (site , d , a , s) ? ; } Ok (()) } (Ty :: Fn (a1 , r1) , Ty :: Fn (a2 , r2)) => { unify (site , a1 , a2 , s) ? ; unify (site , r1 , r2 , s) } (Ty :: Seq (e1 , n1) , Ty :: Seq (e2 , n2)) if n1 == n2 => unify (site , e1 , e2 , s) , (Ty :: Binary (Width :: Var (v)) , Ty :: Binary (Width :: Lit (n))) | (Ty :: Ternary (Width :: Var (v)) , Ty :: Ternary (Width :: Lit (n))) => { let carrier = Ty :: Binary (Width :: Lit (* n)) ; match s . get (v) { Some (bound) if * bound != carrier => { let prior = match bound { Ty :: Binary (w) => w . to_string () , other => other . to_string () , } ; Err (CheckError :: new (site , format ! ("width parameter `{v}` would have to be both {prior} and {n} — a width mismatch, not a coercion (DN-42 §4 / VR-5)") ,)) } _ => { s . insert (v . clone () , carrier) ; Ok (()) } } } (Ty :: Binary (Width :: Var (v1)) , Ty :: Binary (Width :: Var (v2))) | (Ty :: Ternary (Width :: Var (v1)) , Ty :: Ternary (Width :: Var (v2))) => { let carrier = Ty :: Binary (Width :: Var (v2 . clone ())) ; match s . get (v1) { Some (bound) if * bound != carrier => Err (CheckError :: new (site , format ! ("width parameter `{v1}` would have to be both {bound} and the abstract width \
                         `{v2}` — an undetermined width, not a coercion (DN-42 §4 / VR-5)") ,)) , _ => { s . insert (v1 . clone () , carrier) ; Ok (()) } } } _ if decl == actual => Ok (()) , _ => Err (CheckError :: new (site , format ! ("cannot match {decl} against {actual} (RFC-0007 §11.3 — never a silent swap)") ,)) , } }

# [doc = " Resolve a surface [`TypeRef`] to a checked [`Ty`], with the type parameters `tyvars` in scope"] # [doc = " (RFC-0007 §11.2): a `Named(name, [])` whose `name` is a type parameter resolves to [`Ty::Var`];"] # [doc = " any other `Named` is a data type whose **arity is checked** against its declaration (`List<A>`"] # [doc = " applied to the wrong number of arguments is an explicit error, never a guess). VSA types resolve"] # [doc = " concretely as of M-892 (their surface model ident canonicalized to the kernel model id). The"] # [doc = " guarantee index is *allowed* and returned alongside (checked dynamically at"] # [doc = " stage 0 — RFC-0007 §4.3). `tyvars` is `&[]` in a monomorphic context."] pub (crate) fn resolve_ty (site : & str , types : & BTreeMap < String , DataInfo > , tyvars : & [String] , t : & TypeRef ,) -> Result < (Ty , Option < Strength >) , CheckError > { let base = match & t . base { BaseType :: Binary (WidthRef :: Lit (n)) => Ty :: Binary (Width :: Lit (* n)) , BaseType :: Binary (WidthRef :: Name (v)) => Ty :: Binary (Width :: Var (v . clone ())) , BaseType :: Ternary (WidthRef :: Lit (m)) => Ty :: Ternary (Width :: Lit (* m)) , BaseType :: Ternary (WidthRef :: Name (v)) => Ty :: Ternary (Width :: Var (v . clone ())) , BaseType :: Dense (d , s) => Ty :: Dense (* d , * s) , BaseType :: Substrate (tag) => Ty :: Substrate (tag . clone ()) , BaseType :: Seq { elem , len } => { let (elem_ty , _) = resolve_ty (site , types , tyvars , elem) ? ; Ty :: Seq (Box :: new (elem_ty) , * len) } BaseType :: Bytes => Ty :: Bytes , BaseType :: Float => Ty :: Float , BaseType :: Vsa { model , dim , sparsity , } => Ty :: Vsa { model : vsa_kernel_model_id (model) , dim : * dim , sparsity : sparsity . clone () , } , BaseType :: Named (name , args) => { if args . is_empty () && tyvars . iter () . any (| v | v == name) { Ty :: Var (name . clone ()) } else { let Some (decl) = lookup_data (types , name) else { return Err (CheckError :: new (site , format ! ("unknown type `{name}`"))) ; } ; if let Some (home) = data_home_mismatch (name , decl) { return Err (CheckError :: new (site , data_home_mismatch_message (name , home , decl) ,)) ; } if args . len () != decl . params . len () { return Err (CheckError :: new (site , format ! ("`{name}` takes {} type argument(s), got {} (RFC-0007 §11.3)" , decl . params . len () , args . len ()) ,)) ; } let qname = qualify_type_name (& decl . home , ty_local_name (name)) ; let mut resolved = Vec :: with_capacity (args . len ()) ; for a in args { resolved . push (resolve_ty (site , types , tyvars , a) ? . 0) ; } Ty :: Data (qname , resolved) } } BaseType :: Ambient (_) => { return Err (CheckError :: new (site , "internal: an unresolved paradigm-less repr `{…}` reached the checker — the \
                 ambient resolution pass should have filled it (RFC-0012 §4.3)" ,)) ; } BaseType :: Fn (param , ret) => { let (param_ty , _) = resolve_ty (site , types , tyvars , param) ? ; let (ret_ty , _) = resolve_ty (site , types , tyvars , ret) ? ; Ty :: Fn (Box :: new (param_ty) , Box :: new (ret_ty)) } BaseType :: Tuple (elems) => { let n = elems . len () ; let tname = tuple_type_name (n) ; if ! types . contains_key (& tname) { return Err (CheckError :: new (site , format ! ("internal: synthetic tuple type `{tname}` not registered — \
                         `register_tuple_types` must run before the checker (M-826; never silent)") ,)) ; } let mut resolved = Vec :: with_capacity (n) ; for e in elems { resolved . push (resolve_ty (site , types , tyvars , e) ? . 0) ; } Ty :: Data (tname , resolved) } } ; Ok ((base , t . guarantee)) }

impl NoduleImports { # [doc = " The never-silent glob-vs-glob ambiguity refusal for `name`, if it is ambiguous here (G2)."] # [doc = " Returns `None` when the name is unambiguous (so the caller falls through to its own"] # [doc = " unknown-name diagnostic)."] fn ambiguity_error (& self , site : & str , name : & str) -> Option < CheckError > { self . ambiguous . contains (name) . then (| | { CheckError :: new (site , format ! ("`{name}` is ambiguous — imported by more than one glob `use … .*` in this \
                     nodule; import it explicitly (`use <path>.{name}`) to disambiguate (M-662; \
                     never a silent winner — G2)") ,) }) } }

# [doc = " **§4.1 IL-grammar RHS type-check** of a registered `lower` rule (DN-54 §4.1 / M-812-cont),"] # [doc = " **shared** (M-1054 Stage 1b) with [`Cx::check_sugar_call`]'s call-site accept path — see"] # [doc = " [`infer_expr_rule_rhs_type`], the one `Cx::infer` pass both now run. The RHS must type-check as"] # [doc = " an L1 expression with the rule's type parameters in scope as abstract type-variables (the rule is"] # [doc = " parametric over the type it is derived for) **and**, since M-1054 Stage 1b, its declared **value**"] # [doc = " parameters ([`LowerDecl::value_params`]) bound to their declared types — see"] # [doc = " [`infer_expr_rule_rhs_type`]'s own doc comment for why. An ill-typed / ill-formed RHS is an"] # [doc = " explicit refusal at definition time — so no `derive` site (nor, since Stage 1b, a value-parametric"] # [doc = " call site) can invoke a rule that would produce broken L0. Run over the whole rule set *after*"] # [doc = " §4.2 acyclicity (so a cyclic set reports the cycle, not an \"unknown name\" for the cycle's"] # [doc = " rule-reference edge)."] # [doc = ""] # [doc = " **Guarantee: `Declared`** (a structural type/grammar check, not a theorem — VR-5) **layered with"] # [doc = " `Empirical`** (M-919; DN-71 Model S §4.2) for any `Substrate`-typed binding the RHS introduces —"] # [doc = " see [`infer_expr_rule_rhs_type`]'s affine-tracker note. No expected type is pinned (a rule may"] # [doc = " lower to any well-typed term) — pure inference. The `@std-sys` gate is held **closed**: a `lower`"] # [doc = " rule is never an FFI escape (the §4.6 structural check already refused any direct `wild`; this is"] # [doc = " defense in depth)."] fn check_lower_rule_rhs_type (ld : & LowerDecl , types : & BTreeMap < String , DataInfo > , fns : & BTreeMap < String , FnDecl > , traits : & BTreeMap < String , TraitInfo > , instances : & BTreeMap < (String , String) , InstanceInfo > , imports : & NoduleImports , lower_rules : & BTreeMap < String , LowerDecl > ,) -> Result < () , CheckError > { if let crate :: ast :: LowerRhs :: Impl (id) = & ld . rhs { let Some (tr) = traits . get (& id . trait_name) else { return Err (CheckError :: new (& ld . name , format ! ("`lower {}`'s item RHS is `impl {} for …`, but trait `{}` is not declared in \
                     scope (DN-54 §10.3 Model A; a derive template's trait must be visible — never \
                     silent, G2)" , ld . name , id . trait_name , id . trait_name) ,)) ; } ; check_impl_method_set (tr , id) . map_err (| e | { CheckError :: new (& ld . name , format ! ("`lower {}`'s item RHS `impl {} for …`: {}" , ld . name , id . trait_name , e . message) ,) }) ? ; return Ok (()) ; } let rhs = ld . expr_rhs () . expect ("item-shaped rules returned above; this is the expression arm") ; infer_expr_rule_rhs_type (ld , rhs , types , fns , traits , instances , imports , lower_rules) ? ; Ok (()) }

# [doc = " Validate a `derive Name for T` use-site application (DN-54 §4 / M-812 / DN-38 §8.1)."] # [doc = ""] # [doc = " **Guarantee: `Declared`** (name-resolution + target-type + arity checks; the RHS instantiation"] # [doc = " + elaboration run at elaboration time, `Empirical` — VR-5)."] # [doc = ""] # [doc = " Checks (all never-silent, G2):"] # [doc = " - **Rule resolution**: `Name` must resolve to a registered `lower` rule in `lower_rules`"] # [doc = "   (earlier declarations in the same Pass 3e loop are already registered)."] # [doc = " - **Target type well-formedness**: `for_ty` must resolve to a real type (DN-54 §4)."] fn check_derive_application (dd : & DeriveDecl , lower_rules : & BTreeMap < String , LowerDecl > , types : & BTreeMap < String , DataInfo > ,) -> Result < () , CheckError > { if ! lower_rules . contains_key (& dd . name) { return Err (CheckError :: new (& dd . name , format ! ("`derive {}` references an unknown generative-lowering rule — declare it first \
                 with `lower {} […] = <rhs>` (DN-54 §4 / M-812; rule must be visible before use, \
                 G2). Did you spell the rule name correctly?" , dd . name , dd . name) ,)) ; } resolve_ty (& dd . name , types , & [] , & dd . for_ty) ? ; Ok (()) }

# [doc = " One body's effect coverage: `declared ⊇ performed`, where *performed* is the union of each"] # [doc = " callee's declared effects — a known top-level fn (`fns`), else an unqualified trait method"] # [doc = " (`traits`, by name) — **plus the `ffi` effect contributed by any `wild` block** (M-661). Owned-"] # [doc = " `String` sets keep lifetimes simple; the structural walk is shared with totality (one traversal,"] # [doc = " no bespoke depth-guarded recursion). Deterministic order ⇒ a stable first-miss diagnostic. The"] # [doc = " M-353 runtime budget ledger is a separate concern (not consulted here)."] fn check_body_effect_coverage (fns : & BTreeMap < String , FnDecl > , traits : & BTreeMap < String , TraitInfo > , name : & str , declared_effs : & [String] , body : & Expr ,) -> Result < () , CheckError > { let declared : std :: collections :: BTreeSet < String > = declared_effs . iter () . cloned () . collect () ; let mut performed : std :: collections :: BTreeSet < (String , EffectSource) > = std :: collections :: BTreeSet :: new () ; crate :: totality :: walk_expr (body , & mut | x | { match x { Expr :: App { head , .. } => { if let Expr :: Path (p) = head . as_ref () { if p . 0 . len () == 1 { let callee = & p . 0 [0] ; if let Some (g) = fns . get (callee) { for eff in & g . sig . effects { performed . insert ((eff . clone () , EffectSource :: Call (callee . clone ()))) ; } } else { for tr in traits . values () { for s in & tr . sigs { if & s . name == callee { for eff in & s . effects { performed . insert ((eff . clone () , EffectSource :: Call (callee . clone ()) ,)) ; } } } } } } } } Expr :: Wild (_) => { performed . insert (("ffi" . to_owned () , EffectSource :: Wild)) ; } _ => { } } }) . map_err (| e | CheckError :: new (name , e . to_string ())) ? ; for (eff , source) in & performed { if ! declared . contains (eff) { let via = match source { EffectSource :: Call (callee) => format ! ("via calling `{callee}`") , EffectSource :: Wild => "via a `wild` block (the FFI floor — M-661)" . to_owned () , } ; return Err (CheckError :: new (name , format ! ("`{name}` performs effect `{eff}` ({via}) but does not declare it — add it to \
                     the `!{{…}}` effect annotation (RFC-0014 §4.5 I3: no undeclared effects; never \
                     silent — G2)") ,)) ; } } Ok (()) }

# [doc = " **Trait pass** (RFC-0019 §4.2; LR-2 — guarantee: `Declared`, a structural registry check, not a"] # [doc = " theorem). Register each `trait Tr<params> { fn … }` as a [`TraitInfo`]: reject a duplicate trait"] # [doc = " name; reject duplicate type-parameter names and duplicate method names; and check that **every**"] # [doc = " method signature *resolves* with the trait's params in scope as abstract type-variables (its"] # [doc = " value-param types and return type via [`resolve_ty`]). A trait is a registry entry, never a"] # [doc = " kernel node (KC-3). Every refusal is an explicit [`CheckError`] (G2)."] pub (crate) fn register_traits (types : & BTreeMap < String , DataInfo > , nodule : & Nodule ,) -> Result < BTreeMap < String , TraitInfo > , CheckError > { let mut traits : BTreeMap < String , TraitInfo > = BTreeMap :: new () ; for item in & nodule . items { let Item :: Trait (td) = item else { continue } ; let site = & td . name ; if let Some (dup) = first_duplicate (& td . params) { return Err (CheckError :: new (site , format ! ("duplicate type parameter `{dup}` in trait `{}`" , td . name) ,)) ; } if traits . contains_key (& td . name) { return Err (CheckError :: new (site , "duplicate trait declaration")) ; } let mut seen_methods : std :: collections :: BTreeSet < & str > = std :: collections :: BTreeSet :: new () ; for s in & td . sigs { if ! seen_methods . insert (s . name . as_str ()) { return Err (CheckError :: new (site , format ! ("duplicate method `{}` in trait `{}`" , s . name , td . name) ,)) ; } let mut tyvars = td . params . clone () ; tyvars . extend (s . param_names ()) ; check_sig_resolves (types , site , & tyvars , s) ? ; } traits . insert (td . name . clone () , TraitInfo { name : td . name . clone () , params : td . params . clone () , sigs : td . sigs . clone () , } ,) ; } for tr in traits . values () { for s in & tr . sigs { for tp in & s . params { for b in & tp . bounds { if ! traits . contains_key (& b . name) { return Err (CheckError :: new (& tr . name , format ! ("trait `{}` method `{}`: unknown trait `{}` in the bound `{}: {}` \
                                 (RFC-0019 §4.1 — a method's type-parameter bound must name a \
                                 declared trait)" , tr . name , s . name , b . name , tp . name , b . name) ,)) ; } } } } } Ok (traits) }

# [doc = " Check one `impl`'s method bodies against their **expected** signatures (RFC-0019 §4.5; guarantee:"] # [doc = " `Declared` — a structural check). The expected signature of method `m` is the trait's sig for `m`"] # [doc = " with the trait's params substituted by this impl's `trait_args`; the method body is checked the"] # [doc = " normal fn-body way against those substituted value-param/return types. A signature mismatch"] # [doc = " (wrong param types or arity, wrong return) is an explicit refusal, never silently accepted."] # [allow (clippy :: too_many_arguments)] fn check_impl_methods (types : & BTreeMap < String , DataInfo > , fns : & BTreeMap < String , FnDecl > , traits : & BTreeMap < String , TraitInfo > , instances : & BTreeMap < (String , String) , InstanceInfo > , imports : & NoduleImports , lower_rules : & BTreeMap < String , LowerDecl > , std_sys : bool , id : & ImplDecl ,) -> Result < Vec < FnDecl > , CheckError > { let tr = traits . get (& id . trait_name) . expect ("instance registration checked the trait exists") ; let mut resolved : Vec < FnDecl > = Vec :: with_capacity (id . methods . len ()) ; let (for_ty , _) = resolve_ty (& id . trait_name , types , & [] , & id . for_ty) ? ; let mut trait_args = Vec :: with_capacity (id . trait_args . len ()) ; for a in & id . trait_args { trait_args . push (resolve_ty (& id . trait_name , types , & [] , a) ? . 0) ; } let s = param_subst (& tr . params , & trait_args) ; for method in & id . methods { let req = tr . sigs . iter () . find (| x | x . name == method . sig . name) . expect ("method-set match checked at registration") ; let site = & method . sig . name ; if method . sig . value_params . len () != req . value_params . len () { return Err (CheckError :: new (site , format ! ("impl method `{}` of `{}` takes {} parameter(s), but the trait requires {}" , method . sig . name , tr . name , method . sig . value_params . len () , req . value_params . len ()) ,)) ; } for (mp , rp) in method . sig . value_params . iter () . zip (& req . value_params) { let (got , _) = resolve_ty (site , types , & [] , & mp . ty) ? ; let want = subst_ty (& resolve_ty (site , types , & tr . params , & rp . ty) ? . 0 , & s) ; if got != want { return Err (CheckError :: new (site , format ! ("impl method `{}` parameter `{}`: {}" , method . sig . name , mp . name , edge_mismatch ("type" , & want , & got)) ,)) ; } } let (got_ret , _) = resolve_ty (site , types , & [] , & method . sig . ret) ? ; let want_ret = subst_ty (& resolve_ty (site , types , & tr . params , & req . ret) ? . 0 , & s) ; if got_ret != want_ret { return Err (CheckError :: new (site , format ! ("impl method `{}` return: {}" , method . sig . name , edge_mismatch ("type" , & want_ret , & got_ret)) ,)) ; } let req_effects : std :: collections :: BTreeSet < & str > = req . effects . iter () . map (String :: as_str) . collect () ; let got_effects : std :: collections :: BTreeSet < & str > = method . sig . effects . iter () . map (String :: as_str) . collect () ; if req_effects != got_effects { return Err (CheckError :: new (site , format ! ("impl method `{}` declares effects {} but trait `{}` requires {} — an impl \
                     method's effect annotation must match the trait method's exactly (RFC-0014 \
                     §4.5 I3; never silently widened or narrowed — G2)" , method . sig . name , render_effects (& method . sig . effects) , tr . name , render_effects (& req . effects) ,) ,)) ; } let (body , _ret) = check_fn_body (types , fns , traits , instances , imports , lower_rules , std_sys , method ,) ? ; resolved . push (FnDecl { vis : method . vis , thaw : method . thaw , tier : method . tier , sig : method . sig . clone () , body , }) ; } let _ = for_ty ; Ok (resolved) }

# [doc = " Build the L0 [`Value`] of a representation literal (Q6: a literal *is* its representation —"] # [doc = " width = digit count). Bare integers and lists have no representation family and are refused"] # [doc = " (the typechecker already refuses them; this refusal keeps the bridge honest on its own)."] pub fn lit_value (site : & str , l : & Literal) -> Result < Value , ElabError > { match l { Literal :: Bin (s) => { let bits : Vec < bool > = s . chars () . filter (| c | * c == '0' || * c == '1') . map (| c | c == '1') . collect () ; let width = u32 :: try_from (bits . len ()) . expect ("digit count fits u32") ; Value :: new (Repr :: Binary { width } , Payload :: Bits (bits) , Meta :: exact (Provenance :: Root) ,) . map_or_else (| e | residual (site , format ! ("malformed binary literal: {e}")) , Ok ,) } Literal :: Trit (s) => { let trits : Vec < Trit > = s . chars () . map (| c | match c { '+' => Ok (Trit :: Pos) , '0' => Ok (Trit :: Zero) , '-' => Ok (Trit :: Neg) , other => Err (other) , }) . collect :: < Result < _ , _ > > () . map_or_else (| c | residual (site , format ! ("non-trit char {c:?} in ternary literal")) , Ok ,) ? ; let width = u32 :: try_from (trits . len ()) . expect ("trit count fits u32") ; Value :: new (Repr :: Ternary { trits : width } , Payload :: Trits (trits) , Meta :: exact (Provenance :: Root) ,) . map_or_else (| e | residual (site , format ! ("malformed ternary literal: {e}")) , Ok ,) } Literal :: Bytes (s) => { let hex : String = s . chars () . filter (| c | * c != '_') . collect () ; let mut bytes = Vec :: with_capacity (hex . len () / 2) ; let chars : Vec < char > = hex . chars () . collect () ; for pair in chars . chunks (2) { let hs : String = pair . iter () . collect () ; match u8 :: from_str_radix (& hs , 16) { Ok (b) => bytes . push (b) , Err (_) => { return residual (site , format ! ("non-hex byte pair {hs:?} in `0x…` literal")) } } } Value :: new (Repr :: Bytes , Payload :: Bytes (bytes) , Meta :: exact (Provenance :: Root) ,) . map_or_else (| e | residual (site , format ! ("malformed byte literal: {e}")) , Ok ,) } Literal :: Str (s) => Value :: new (Repr :: Bytes , Payload :: Bytes (s . as_bytes () . to_vec ()) , Meta :: exact (Provenance :: Root) ,) . map_or_else (| e | residual (site , format ! ("malformed string literal: {e}")) , Ok ,) , Literal :: Float (s) => { let x : f64 = match s . parse () { Ok (x) => x , Err (_) => { return residual (site , format ! ("internal: malformed float literal text {s:?} reached elaboration") ,) } } ; Value :: new (Repr :: Float { width : FloatWidth :: F64 , } , Payload :: Float (x) , Meta :: exact (Provenance :: Root) ,) . map_or_else (| e | residual (site , format ! ("malformed float literal: {e}")) , Ok ,) } Literal :: Int (_) => residual (site , "a bare integer literal has no representation family (Q6)" ,) , Literal :: AmbientInt (_ , _) => residual (site , "internal: an unresolved ambient bare decimal reached elaboration — the checker \
             resolves its width before the L0 bridge runs (RFC-0012 §4.3)" ,) , Literal :: List (_) => residual (site , "internal: a list literal reached `lit_value` — it lowers through `expr_inner` (the \
             element expressions need elaboration; RFC-0032 D3)" ,) , } }

fn elaborate_colony_inner (env : & Env , entry : & str) -> Result < Vec < Node > , ElabError > { let mono_env = crate :: mono :: monomorphize (env , entry) ? ; let (mut el , binders , fd) = elab_prelude (& mono_env , entry , false) ? ; let Expr :: Colony (hyphae) = & fd . body else { return residual (entry , "the entry body is not a `colony` — `elaborate_colony` lowers a colony to its per-hypha \
             closed L0 programs (the concurrent path); use `elaborate` for the sequentialized form" ,) ; } ; if hyphae . is_empty () { return residual (entry , "internal: an empty `colony` reached elaboration — the parser requires ≥ 1 hypha \
             (RFC-0008 §4.7)" ,) ; } let mut stack = vec ! [entry . to_owned ()] ; let mut programs = Vec :: with_capacity (hyphae . len ()) ; for h in hyphae { let body = el . expr (& mut stack , & [] , & h . body) ? ; let node = match & h . forage { None => body , Some (policy) => { forage_reject_if_empty (entry , h) ? ; let policy_node = el . expr (& mut stack , & [] , policy) ? ; Node :: Let { id : el . fresh ("forage_policy") , bound : Box :: new (policy_node) , body : Box :: new (body) , } } } ; programs . push (wrap_in_binders (binders . clone () , node)) ; } Ok (programs) }

fn elaborate_reclaim_inner (env : & Env , entry : & str) -> Result < (Node , Node) , ElabError > { let mono_env = crate :: mono :: monomorphize (env , entry) ? ; let (mut el , binders , fd) = elab_prelude (& mono_env , entry , false) ? ; let Expr :: Reclaim { policy , body } = & fd . body else { return residual (entry , "the entry body is not a `reclaim` — `elaborate_reclaim` lowers a reclaim to its \
             (policy, body) closed L0 programs (the supervised path); use `elaborate` for the \
             sequential-reference form" ,) ; } ; let mut stack = vec ! [entry . to_owned ()] ; let policy_node = el . expr (& mut stack , & [] , policy) ? ; let body_node = el . expr (& mut stack , & [] , body) ? ; Ok ((wrap_in_binders (binders . clone () , policy_node) , wrap_in_binders (binders , body_node) ,)) }

# [doc = " Shared front-end of [`elaborate`]/[`elaborate_colony`]: validate the entry is a closed (nullary,"] # [doc = " no dynamic guarantee) definition, build the data registry, decompose the reachable call graph into"] # [doc = " callee-first recursive SCCs (Tarjan), and elaborate each SCC's recursive binder. Returns the"] # [doc = " primed [`Elab`], the callee-first binder list, and the entry's [`FnDecl`]. DRY: the recursion"] # [doc = " machinery is identical whether the entry body is sequentialized to one `Node` or split per-hypha."] # [doc = ""] # [doc = " `allow_value_params` relaxes the nullary-entry check for exactly one caller"] # [doc = " ([`elaborate_value_parametric_rule`], M-1054 Stage 1): a `lower` rule's synthetic entry is not"] # [doc = " closed, it has the rule's own value parameters in scope, so it cannot go through the ordinary"] # [doc = " closed-entry validation every other caller (`elaborate`/`elaborate_direct`/`elaborate_colony`/"] # [doc = " `elaborate_reclaim`) still requires (they all pass `false`, unchanged behavior)."] fn elab_prelude < 'e > (env : & 'e Env , entry : & str , allow_value_params : bool ,) -> Result < (Elab < 'e > , Vec < RecBinding > , & 'e crate :: ast :: FnDecl) , ElabError > { let Some (fd) = env . fns . get (entry) else { return Err (ElabError :: UnknownFn (entry . to_owned ())) ; } ; if ! allow_value_params && ! fd . sig . value_params . is_empty () { return residual (entry , "the entry has value parameters — v0 elaborates closed (nullary) entries; \
             apply it from a nullary definition" ,) ; } if ! fd . sig . params . is_empty () { return residual (entry , "the entry is generic — a generic definition's L0 lowering is staged (monomorphization; \
             RFC-0007 §11.3, the M-657 follow-up). Elaborate a concrete (monomorphic) entry." ,) ; } let registry = build_registry (env) ? ; let sccs = recursive_sccs (env , entry) ? ; let mut el = Elab { env , registry , fresh : 0 , rec : BTreeMap :: new () , depth : 0 , } ; for scc in & sccs { for f in scc { let kf = el . fresh (f) ; el . rec . insert (f . clone () , kf) ; } } let mut binders : Vec < RecBinding > = Vec :: with_capacity (sccs . len ()) ; for scc in & sccs { if scc . len () == 1 { let f = & scc [0] ; let kf = el . rec [f] . clone () ; let fix = Box :: new (el . elab_recursive_fn (f , & kf) ?) ; binders . push (RecBinding :: Single { var : kf , fix }) ; } else { let mut defs : Vec < (String , Box < Node >) > = Vec :: with_capacity (scc . len ()) ; for f in scc { let kf = el . rec [f] . clone () ; defs . push ((kf , Box :: new (el . elab_fn_lam (f) ?))) ; } binders . push (RecBinding :: Group (defs)) ; } } Ok ((el , binders , fd)) }

impl core :: fmt :: Display for L1Error { fn fmt (& self , f : & mut core :: fmt :: Formatter < '_ >) -> core :: fmt :: Result { match self { L1Error :: FuelExhausted => write ! (f , "evaluation exceeded its step budget") , L1Error :: DepthExceeded { limit } => write ! (f , "evaluation exceeded its recursion-depth budget ({limit}) — explicit by design \
                 (raise with `Evaluator::with_depth`; the host stack is not the limit)") , L1Error :: Kernel (e) => write ! (f , "kernel refusal: {e}") , L1Error :: GuaranteeTooWeak { site , asserted , actual , } => write ! (f , "in `{site}`: asserted `@ {asserted:?}` but the value's tag is {actual:?} — an \
                 annotation may only weaken (VR-5)") , L1Error :: Unsupported { site , what } => write ! (f , "in `{site}`: {what}") , L1Error :: Stuck { site , why } => write ! (f , "in `{site}`: stuck — {why} (the typechecker should have refused this program)") , L1Error :: EffectBudget (e) => write ! (f , "{e}") , L1Error :: Forage (e) => write ! (f , "{e}") , } } }

# [doc = " The depth-tracked worker behind [`pattern_binders`] (M-866) — see [`free_vars_at`] for the"] # [doc = " shared discipline this mirrors."] fn pattern_binders_at (pat : & Pattern , bound : & mut BTreeSet < String > , added : & mut Vec < String > , depth : u32 ,) -> Result < () , WalkDepthExceeded > { let depth = depth + 1 ; if depth > MAX_WALK_DEPTH { return Err (WalkDepthExceeded { limit : MAX_WALK_DEPTH , }) ; } match pat { Pattern :: Wildcard | Pattern :: Lit (_) => { } Pattern :: Ident (n) => { if bound . insert (n . clone ()) { added . push (n . clone ()) ; } } Pattern :: Ctor (_ , subs) => { for s in subs { pattern_binders_at (s , bound , added , depth) ? ; } } Pattern :: Tuple (subs) => { for s in subs { pattern_binders_at (s , bound , added , depth) ? ; } } Pattern :: Or (_) => panic ! ("internal: Pattern::Or reached mono::pattern_binders — or-patterns must be \
             desugared by the checker before any downstream pass \
             (invariant violation — report this)") , } Ok (()) }
